// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {


	if(isLoading){
		shoHideFields();
		return;
	}

	//If you set it to a value that hide fields, but the original did not, the fields are hidden, but don't get redisplayed 
	//if(newValue!=oldValue){ 
		shoHideFields();
	//}

	function shoHideFields() {
		var isStandard = g_scratchpad.taskType == 'Standard';
		var isAcknowledgement = g_scratchpad.taskType ==  'Acknowledgement';
		var isInformation_only = g_scratchpad.taskType == 'Information Only';

		var isApproval_with_Signature = g_scratchpad.taskType == 'Approval with signature';
		var isApproval_without_Signature = g_scratchpad.taskType == 'Approval without signature';
		var isConcur_with_Signature = g_scratchpad.taskType == 'Concur with signature';
		var isConcur_without_Signature = g_scratchpad.taskType == 'Concur without signature';

		//Duration fields
		g_form.setDisplay("work_start", (!isAcknowledgement && !isInformation_only));
		g_form.setDisplay("work_end", (!isAcknowledgement && !isInformation_only));
		g_form.setDisplay("expected_start", (!isAcknowledgement && !isInformation_only));
		g_form.setDisplay("calendar_duration", (!isAcknowledgement && !isInformation_only));
		//Assignment fields
		g_form.setDisplay("u_reviewer", (!isAcknowledgement && !isInformation_only));
		//Risk section
		g_form.setSectionDisplay('risk', (!isAcknowledgement && !isInformation_only));

		//STRY0086943 - Response & Reviewer Decision section
		var inAssigned = (g_scratchpad.currentState == "1");
		var inUnassigned = (g_scratchpad.currentState == "-5");
		var inWaiting = (g_scratchpad.currentState == "-3");
		var inNew = (g_scratchpad.currentState == ("New" || ""));

		var standardEarlyState = (isStandard && (inUnassigned || inWaiting || inNew));
		var isReviewType = isApproval_with_Signature || isApproval_without_Signature || isConcur_with_Signature ||isConcur_without_Signature;
		var reviewtypeEarlyState = isReviewType && (inAssigned || inUnassigned || inWaiting || inNew);
		var earlyState = standardEarlyState || reviewtypeEarlyState;

		var earlyStateWithComments = ((earlyState ) && (g_form.getValue('response') != '' 
													|| g_form.getValue('rework_comments') != ''
													|| g_form.getValue('decision') != ''	
													|| g_form.getValue('comments_dt') != ''
													|| g_form.getValue('u_cancellation_reason') != '' )
									);
		g_form.setSectionDisplay('response_reviewerdecision', 
								((!isAcknowledgement && !isInformation_only) && (isStandard || earlyStateWithComments || !earlyState))
								);
		// Review Required
		g_form.setDisplay("provide_response", isStandard);

	}
}
